PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?attendance
WHERE {
  ?game wdt:P31 wd:Q3924307 ;
        wdt:P710 wd:Q334634 ;
        wdt:P710 wd:Q650840 ;
        wdt:P1110 ?attendance .
}
ORDER BY DESC(?attendance)
OFFSET 2
LIMIT 1

