PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wikibase: <http://wikiba.se/ontology#>

SELECT (xsd:integer(REPLACE(STR(?attendanceNode), "\\D+", "")) AS ?attendanceNum)
WHERE {
  {
    ?game wdt:P1995 wd:Q334634 ;
          wdt:P1996 wd:Q650840 ;
          wdt:P1110 ?attendanceNode .
  }
  UNION
  {
    ?game wdt:P1995 wd:Q650840 ;
          wdt:P1996 wd:Q334634 ;
          wdt:P1110 ?attendanceNode .
  }
  FILTER (?attendanceNode != "")
  FILTER (CONTAINS(STR(?attendanceNode), "") || isNumeric(xsd:integer(REPLACE(STR(?attendanceNode), ",", ""))))
}
ORDER BY DESC(xsd:integer(REPLACE(STR(?attendanceNode), ",", "")))
LIMIT 1 OFFSET 2

best_attempt.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?attendance
WHERE {
  VALUES (?home ?away) {
    (wd:Q334634 wd:Q650840)
    (wd:Q650840 wd:Q334634)
  }
  ?game wdt:P1995 ?home ;
        wdt:P1996 ?away ;
        wdt:P1110 ?attendance .
  BIND(xsd:integer(REPLACE(STR(?attendance), "[^0-9]", "")) AS ?attNum)
  FILTER (?attNum > 0)
}
ORDER BY DESC(?attNum)
LIMIT 1 OFFSET 2
